import { type PropsWithChildren, type HTMLAttributes } from 'react';

import { primaryInfo } from './styles.sty.js';

/**
 * @internal
 */
export type PrimaryAtomProps = PropsWithChildren<
  HTMLAttributes<HTMLDivElement>
>;

/**
 * @internal
 **/
export const PrimaryAtom = ({ children, ...rest }: PrimaryAtomProps) => {
  return (
    <div className={primaryInfo} {...rest}>
      {children}
    </div>
  );
};
PrimaryAtom['displayName'] = 'PrimaryAtom';
